  var e: nat := 0;
  var r: nat := 0;
  var o: nat := 0;
  var n: nat := 0;

  for i := 0 to |s|
    invariant z == CountChar(s[..i], 'z')
    invariant e == CountChar(s[..i], 'e')
    invariant r == CountChar(s[..i], 'r')
    invariant o == CountChar(s[..i], 'o')
    invariant n == CountChar(s[..i], 'n')
  {
    CountCharStep(s, i, 'z');
    CountCharStep(s, i, 'e');
    CountCharStep(s, i, 'r');
    CountCharStep(s, i, 'o');
    CountCharStep(s, i, 'n');
    if s[i] == 'z' {
